1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description:
5	-- Block to serve as an async FIFO for AXI Streams. This block also allows the
6	-- bus to be compress/expanded, allowing different standard sizes on each side
7	-- of the FIFO. Re-sizing is always little endian.
8	-------------------------------------------------------------------------------
9	-- This file is part of 'SLAC Firmware Standard Library'.
10	-- It is subject to the license terms in the LICENSE.txt file found in the
11	-- top-level directory of this distribution and at:
12	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
13	-- No part of 'SLAC Firmware Standard Library', including this file,
14	-- may be copied, modified, propagated, or distributed except according to
15	-- the terms contained in the LICENSE.txt file.
16	-------------------------------------------------------------------------------
17	
18	library ieee;
19	use ieee.std_logic_1164.all;
20	use ieee.std_logic_unsigned.all;
21	use ieee.std_logic_arith.all;
22	
23	library surf;
24	use surf.StdRtlPkg.all;
25	use surf.AxiStreamPkg.all;
26	
27	entity AxiStreamFifoV2 is
28	   generic (
29	      -- General Configurations
30	      TPD_G             : time                  := 1 ns;
31	      RST_POLARITY_G    : sl                    := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
32	      RST_ASYNC_G       : boolean               := false;
33	      INT_PIPE_STAGES_G : natural range 0 to 16 := 0;  -- Internal FIFO setting
34	      PIPE_STAGES_G     : natural range 0 to 16 := 1;
35	      SLAVE_READY_EN_G  : boolean               := true;
36	
37	      -- Valid threshold should always be 1 when using interleaved tdest
38	      VALID_THOLD_G       : integer range 0 to (2**24) := 1;  -- =1 = normal operation
39	                                        -- =0 = only when frame ready
40	                                                              -- >1 = only when frame ready or # entries
41	      VALID_BURST_MODE_G  : boolean                    := false;  -- only used in VALID_THOLD_G>1
42	      -- FIFO configurations
43	      GEN_SYNC_FIFO_G     : boolean                    := false;
44	      FIFO_ADDR_WIDTH_G   : integer range 4 to 48      := 9;
45	      FIFO_FIXED_THRESH_G : boolean                    := true;
46	      FIFO_PAUSE_THRESH_G : integer range 1 to (2**24) := 1;
47	      SYNTH_MODE_G        : string                     := "inferred";
48	      MEMORY_TYPE_G       : string                     := "block";
49	
50	      -- Internal FIFO width select, "WIDE", "NARROW" or "CUSTOM"
51	      -- WIDE uses wider of slave / master. NARROW  uses narrower.
52	      -- CUSTOM uses passed FIFO_DATA_WIDTH_G
53	      INT_WIDTH_SELECT_G : string                                          := "WIDE";
54	      INT_DATA_WIDTH_G   : natural range 1 to AXI_STREAM_MAX_TKEEP_WIDTH_C := 16;
55	
56	      -- If VALID_THOLD_G /=1, FIFO that stores on tLast txns can be smaller.
57	      -- Set to 0 for same size as primary fifo (default)
58	      -- Set >4 for custom size.
59	      -- Use at own risk. Overflow of tLast fifo is not checked
60	      LAST_FIFO_ADDR_WIDTH_G : integer range 0 to 48 := 0;
61	
62	      -- Index = 0 is output, index = n is input
63	      CASCADE_PAUSE_SEL_G : integer range 0 to (2**24) := 0;
64	      CASCADE_SIZE_G      : integer range 1 to (2**24) := 1;
65	
66	      -- AXI Stream Port Configurations
67	      SLAVE_AXI_CONFIG_G  : AxiStreamConfigType;
68	      MASTER_AXI_CONFIG_G : AxiStreamConfigType);
69	   port (
70	
71	      -- Slave Port
72	      sAxisClk    : in  sl;
73	      sAxisRst    : in  sl;
74	      sAxisMaster : in  AxiStreamMasterType;
75	      sAxisSlave  : out AxiStreamSlaveType;
76	      sAxisCtrl   : out AxiStreamCtrlType := AXI_STREAM_CTRL_INIT_C;
77	
78	      -- FIFO status & config , synchronous to sAxisClk, be careful when using with
79	      -- output pipeline stages
80	      fifoPauseThresh : in  slv(FIFO_ADDR_WIDTH_G-1 downto 0) := (others => '1');
81	      fifoWrCnt       : out slv(FIFO_ADDR_WIDTH_G-1 downto 0);
82	      fifoFull        : out sl;
83	
84	      -- Master Port
85	      mAxisClk    : in  sl;
86	      mAxisRst    : in  sl;
87	      mAxisMaster : out AxiStreamMasterType;
88	      mAxisSlave  : in  AxiStreamSlaveType;
89	      mTLastTUser : out slv(7 downto 0));  -- when VALID_THOLD_G /= 1, used to look ahead at tLast's tUser
90	end AxiStreamFifoV2;
91	
92	architecture rtl of AxiStreamFifoV2 is
93	
94	   constant LAST_FIFO_ADDR_WIDTH_C : integer range 4 to 48 :=
95	      ite(LAST_FIFO_ADDR_WIDTH_G < 4, FIFO_ADDR_WIDTH_G, LAST_FIFO_ADDR_WIDTH_G);
96	
97	   -- Generate configuration for FIFO
98	   constant FIFO_CONFIG_C : AxiStreamConfigType := (
99	
100	      -- Enable strobe only if used on both sides
101	      TSTRB_EN_C => SLAVE_AXI_CONFIG_G.TSTRB_EN_C and MASTER_AXI_CONFIG_G.TSTRB_EN_C,
102	
103	      -- Determine FIFO data bytes
104	      TDATA_BYTES_C => ite(INT_WIDTH_SELECT_G = "CUSTOM", INT_DATA_WIDTH_G,
105	                           ite(INT_WIDTH_SELECT_G = "WIDE",
106	
107	                               -- Using wider of the two
108	                               ite(SLAVE_AXI_CONFIG_G.TDATA_BYTES_C > MASTER_AXI_CONFIG_G.TDATA_BYTES_C,
109	                                   SLAVE_AXI_CONFIG_G.TDATA_BYTES_C, MASTER_AXI_CONFIG_G.TDATA_BYTES_C),
110	
111	                               -- Use narrower of the two
112	                               ite(SLAVE_AXI_CONFIG_G.TDATA_BYTES_C > MASTER_AXI_CONFIG_G.TDATA_BYTES_C,
113	                                   MASTER_AXI_CONFIG_G.TDATA_BYTES_C, SLAVE_AXI_CONFIG_G.TDATA_BYTES_C))),
114	
115	      -- Use the lesser of the two DEST widths
116	      TDEST_BITS_C => ite(SLAVE_AXI_CONFIG_G.TDEST_BITS_C > MASTER_AXI_CONFIG_G.TDEST_BITS_C,
117	                          MASTER_AXI_CONFIG_G.TDEST_BITS_C, SLAVE_AXI_CONFIG_G.TDEST_BITS_C),
118	
119	      -- Use the lesser of the two ID widths
120	      TID_BITS_C => ite(SLAVE_AXI_CONFIG_G.TID_BITS_C > MASTER_AXI_CONFIG_G.TID_BITS_C,
121	                        MASTER_AXI_CONFIG_G.TID_BITS_C, SLAVE_AXI_CONFIG_G.TID_BITS_C),
122	
123	      -- Use the lesser of the two USER widths
124	      TUSER_BITS_C => ite(SLAVE_AXI_CONFIG_G.TUSER_BITS_C > MASTER_AXI_CONFIG_G.TUSER_BITS_C,
125	                          MASTER_AXI_CONFIG_G.TUSER_BITS_C, SLAVE_AXI_CONFIG_G.TUSER_BITS_C),
126	
127	      -- Use slave settings for tkeep and tuser mode
128	      TKEEP_MODE_C => SLAVE_AXI_CONFIG_G.TKEEP_MODE_C,
129	      TUSER_MODE_C => SLAVE_AXI_CONFIG_G.TUSER_MODE_C);
130	
131	   constant FIFO_BITS_C : integer := getSlvSize(FIFO_CONFIG_C);
132	
133	   constant FIFO_USER_BITS_C : integer := FIFO_CONFIG_C.TUSER_BITS_C;
134	
135	   ----------------
136	   -- FIFO Signals
137	   ----------------
138	
139	   signal fifoWriteMaster   : AxiStreamMasterType;
140	   signal fifoWriteSlave    : AxiStreamSlaveType;
141	   signal fifoReadMaster    : AxiStreamMasterType;
142	   signal fifoReadSlave     : AxiStreamSlaveType;
143	   signal fifoDin           : slv(FIFO_BITS_C-1 downto 0);
144	   signal fifoWrite         : sl;
145	   signal fifoWriteLast     : sl;
146	   signal fifoWriteUser     : slv(maximum(FIFO_USER_BITS_C-1, 0) downto 0) := (others => '0');
147	   signal fifoWrCount       : slv(FIFO_ADDR_WIDTH_G-1 downto 0);
148	   signal fifoRdCount       : slv(FIFO_ADDR_WIDTH_G-1 downto 0);
149	   signal fifoAFull         : sl;
150	   signal fifoReady         : sl;
151	   signal fifoPFull         : sl;
152	   signal fifoPFullVec      : slv(CASCADE_SIZE_G-1 downto 0);
153	   signal fifoPEmptyVec     : slv(CASCADE_SIZE_G-1 downto 0);
154	   signal fifoUpperNotEmpty : slv(CASCADE_SIZE_G-1 downto 0);
155	   signal fifoDout          : slv(FIFO_BITS_C-1 downto 0);
156	   signal fifoRead          : sl;
157	   signal fifoReadLast      : sl;
158	   signal fifoReadUser      : slv(maximum(FIFO_USER_BITS_C-1, 0) downto 0);
159	   signal fifoValidInt      : sl;
160	   signal fifoValid         : sl;
161	   signal fifoValidLast     : sl;
162	   signal fifoInFrame       : sl;
163	
164	   signal burstEn    : sl;
165	   signal burstLast  : sl;
166	   signal burstCnt   : natural range 0 to VALID_THOLD_G := 0;
167	   signal firstCycle : sl;
168	
169	   signal sideBand : Slv8Array(1 downto 0);
170	
171	   ---------------
172	   -- Sync Signals
173	   ---------------
174	   signal axisMaster : AxiStreamMasterType;
175	   signal axisSlave  : AxiStreamSlaveType;
176	
177	begin
178	
179	   -- Can't use tkeep_fixed on master side when resizing or if not on slave side
180	   assert (not (MASTER_AXI_CONFIG_G.TKEEP_MODE_C = TKEEP_FIXED_C and
181	                SLAVE_AXI_CONFIG_G.TKEEP_MODE_C /= TKEEP_FIXED_C))
182	      report "AxiStreamFifoV2: Can't have TKEEP_MODE = TKEEP_FIXED on master side if not on slave side"
183	      severity failure;
184	
185	   -------------------------
186	   -- Slave Resize
187	   -------------------------
188	   U_SlaveResize : entity surf.AxiStreamGearbox
189	      generic map (
190	         TPD_G               => TPD_G,
191	         RST_POLARITY_G      => RST_POLARITY_G,
192	         RST_ASYNC_G         => RST_ASYNC_G,
193	         READY_EN_G          => SLAVE_READY_EN_G,
194	         SLAVE_AXI_CONFIG_G  => SLAVE_AXI_CONFIG_G,
195	         MASTER_AXI_CONFIG_G => FIFO_CONFIG_C)
196	      port map (
197	         axisClk     => sAxisClk,
198	         axisRst     => sAxisRst,
199	         sAxisMaster => sAxisMaster,
200	         sAxisSlave  => sAxisSlave,
201	         mAxisMaster => fifoWriteMaster,
202	         mAxisSlave  => fifoWriteSlave);
203	
204	   -------------------------
205	   -- FIFO
206	   -------------------------
207	
208	   -- Pause generation
209	   process (fifoPFullVec, fifoPauseThresh, fifoUpperNotEmpty, fifoWrCount,
210	            sAxisClk, sAxisRst) is
211	   begin
212	      if FIFO_FIXED_THRESH_G then
213	         sAxisCtrl.pause <= fifoPFullVec(CASCADE_PAUSE_SEL_G) or uOr(fifoUpperNotEmpty);
214	      elsif (RST_ASYNC_G) and (sAxisRst = RST_POLARITY_G or fifoWrCount >= fifoPauseThresh) then
215	         sAxisCtrl.pause <= '1';
216	      elsif (rising_edge(sAxisClk)) then
217	         if (RST_ASYNC_G = false) and (sAxisRst = RST_POLARITY_G or fifoWrCount >= fifoPauseThresh) then
218	            sAxisCtrl.pause <= '1' after TPD_G;
219	         else
220	            sAxisCtrl.pause <= '0' after TPD_G;
221	         end if;
222	      end if;
223	   end process;
224	
225	   -- Is ready enabled?
226	   fifoReady <= (not fifoAFull) when SLAVE_READY_EN_G else '1';
227	
228	   -- Output a copy of FIFO WR count in case application needs more than one threshold
229	   fifoWrCnt <= fifoWrCount;
230	
231	   -- Map bits
232	   fifoDin       <= toSlv(fifoWriteMaster, FIFO_CONFIG_C);
233	   fifoWrite     <= fifoWriteMaster.tValid and fifoReady;
234	   fifoWriteLast <= fifoWriteMaster.tValid and fifoReady and fifoWriteMaster.tLast;
235	   GET_WR_USER : if (FIFO_USER_BITS_C > 0) generate
236	      fifoWriteUser <= resize(axiStreamGetUserField(FIFO_CONFIG_C, fifoWriteMaster, -1), FIFO_USER_BITS_C);
237	   end generate;
238	   fifoWriteSlave.tReady <= fifoReady;
239	
240	   U_Fifo : entity surf.FifoCascade
241	      generic map (
242	         TPD_G              => TPD_G,
243	         RST_POLARITY_G     => RST_POLARITY_G,
244	         RST_ASYNC_G        => RST_ASYNC_G,
245	         CASCADE_SIZE_G     => CASCADE_SIZE_G,
246	         LAST_STAGE_ASYNC_G => true,
247	         PIPE_STAGES_G      => INT_PIPE_STAGES_G,
248	         GEN_SYNC_FIFO_G    => GEN_SYNC_FIFO_G,
249	         FWFT_EN_G          => true,
250	         SYNTH_MODE_G       => SYNTH_MODE_G,
251	         MEMORY_TYPE_G      => MEMORY_TYPE_G,
252	         SYNC_STAGES_G      => 3,
253	         DATA_WIDTH_G       => FIFO_BITS_C,
254	         ADDR_WIDTH_G       => FIFO_ADDR_WIDTH_G,
255	         INIT_G             => "0",
256	         FULL_THRES_G       => FIFO_PAUSE_THRESH_G,
257	         EMPTY_THRES_G      => 8)  -- few samples to prevent empty chattering on upper FIFO stages
258	      port map (
259	         rst           => sAxisRst,
260	         wr_clk        => sAxisClk,
261	         wr_en         => fifoWrite,
262	         din           => fifoDin,
263	         wr_data_count => fifoWrCount,
264	         overflow      => sAxisCtrl.overflow,
265	         prog_full     => fifoPFull,
266	         progFullVec   => fifoPFullVec,
267	         almost_full   => fifoAFull,
268	         full          => fifoFull,
269	         rd_clk        => mAxisClk,
270	         rd_en         => fifoRead,
271	         progEmptyVec  => fifoPEmptyVec,
272	         dout          => fifoDout,
273	         rd_data_count => fifoRdCount,
274	         valid         => fifoValidInt);
275	
276	   -- Never use lower stage FIFOs in pause calculation
277	   fifoUpperNotEmpty(CASCADE_PAUSE_SEL_G downto 0) <= (others => '0');
278	
279	   GEN_EMPTY_SYNC : if (CASCADE_SIZE_G /= 1) and CASCADE_SIZE_G > (CASCADE_PAUSE_SEL_G+1) generate
280	      U_fifoPEmpty : entity surf.SynchronizerVector
281	         generic map (
282	            TPD_G          => TPD_G,
283	            BYPASS_SYNC_G  => GEN_SYNC_FIFO_G,
284	            OUT_POLARITY_G => '0',      -- Invert the output
285	            WIDTH_G        => CASCADE_SIZE_G-CASCADE_PAUSE_SEL_G-1)
286	         port map (
287	            clk     => sAxisClk,
288	            dataIn  => fifoPEmptyVec(CASCADE_SIZE_G-1 downto CASCADE_PAUSE_SEL_G+1),
289	            dataOut => fifoUpperNotEmpty(CASCADE_SIZE_G-1 downto CASCADE_PAUSE_SEL_G+1));
290	   end generate;
291	
292	   U_LastFifoEnGen : if VALID_THOLD_G /= 1 generate
293	
294	      U_LastFifo : entity surf.FifoCascade
295	         generic map (
296	            TPD_G              => TPD_G,
297	            RST_POLARITY_G     => RST_POLARITY_G,
298	            RST_ASYNC_G        => RST_ASYNC_G,
299	            CASCADE_SIZE_G     => CASCADE_SIZE_G,
300	            LAST_STAGE_ASYNC_G => true,
301	            PIPE_STAGES_G      => INT_PIPE_STAGES_G,
302	            GEN_SYNC_FIFO_G    => GEN_SYNC_FIFO_G,
303	            MEMORY_TYPE_G      => "distributed",
304	            FWFT_EN_G          => true,
305	            SYNC_STAGES_G      => 3,
306	            DATA_WIDTH_G       => maximum(FIFO_USER_BITS_C, 1),
307	            ADDR_WIDTH_G       => LAST_FIFO_ADDR_WIDTH_C,
308	            INIT_G             => "0",
309	            FULL_THRES_G       => 1,
310	            EMPTY_THRES_G      => 1)
311	         port map (
312	            rst    => sAxisRst,
313	            wr_clk => sAxisClk,
314	            wr_en  => fifoWriteLast,
315	            din    => fifoWriteUser,
316	            rd_clk => mAxisClk,
317	            rd_en  => fifoReadLast,
318	            dout   => fifoReadUser,
319	            valid  => fifoValidLast);
320	
321	      U_PreFillMode : if ((VALID_BURST_MODE_G = false) or (VALID_THOLD_G = 0)) generate
322	
323	         process (fifoReadLast, fifoValidInt, mAxisClk, mAxisRst) is
324	         begin
325	            if (RST_ASYNC_G) and (mAxisRst = RST_POLARITY_G or fifoReadLast = '1' or fifoValidInt = '0') then
326	               fifoInFrame <= '0';
327	
328	            elsif (rising_edge(mAxisClk)) then
329	
330	               -- Stop output if fifo valid goes away, wait until another block is ready
331	               if (RST_ASYNC_G = false) and (mAxisRst = RST_POLARITY_G or fifoReadLast = '1' or fifoValidInt = '0') then
332	                  fifoInFrame <= '0' after TPD_G;
333	
334	               -- Start output when a block or end of frame is available
335	               elsif fifoValidLast = '1' or (VALID_THOLD_G /= 0 and fifoRdCount >= VALID_THOLD_G) then
336	                  fifoInFrame <= '1' after TPD_G;
337	
338	               -- Prevent the FIFO from locking up when frame deeper than what the U_Fifo can hold
339	               elsif (fifoAFull = '1') then
340	                  fifoInFrame <= '1' after TPD_G;
341	               end if;
342	
343	            end if;
344	         end process;
345	
346	      end generate;
347	
348	      U_BurstMode : if ((VALID_BURST_MODE_G = true) and (VALID_THOLD_G /= 0)) generate
349	
350	         process (mAxisClk, mAxisRst) is
351	         begin
352	            if (RST_ASYNC_G and mAxisRst = RST_POLARITY_G) then
353	               fifoInFrame <= '0';
354	               burstEn     <= '0';
355	               burstLast   <= '0';
356	               firstCycle  <= '1';
357	            elsif (rising_edge(mAxisClk)) then
358	               if (RST_ASYNC_G = false and mAxisRst = RST_POLARITY_G) or (fifoReadLast = '1') then
359	                  -- Reset the flags
360	                  fifoInFrame <= '0' after TPD_G;
361	                  burstEn     <= '0' after TPD_G;
362	                  burstLast   <= '0' after TPD_G;
363	                  firstCycle  <= '1' after TPD_G;
364	               else
365	                  firstCycle <= '0' after TPD_G;
366	                  -- Check if for burst mode
367	                  if (burstEn = '1') and (burstLast = '0') and (fifoRead = '1') then
368	                     -- Increment the counter
369	                     burstCnt <= burstCnt + 1 after TPD_G;
370	                     -- Check the counter
371	                     if burstCnt = (VALID_THOLD_G-1) then
372	                        -- Reset the flags
373	                        fifoInFrame <= '0' after TPD_G;
374	                        burstEn     <= '0' after TPD_G;
375	                     end if;
376	                  end if;
377	                  if (fifoValidLast = '1') or ((fifoRdCount >= VALID_THOLD_G) and (burstEn = '0') and firstCycle = '0') then
378	                     -- Set the flags
379	                     burstEn     <= '1'           after TPD_G;
380	                     burstLast   <= fifoValidLast after TPD_G;
381	                     fifoInFrame <= '1'           after TPD_G;
382	                     -- Reset the counter
383	                     burstCnt    <= 0             after TPD_G;
384	                  end if;
385	               end if;
386	            end if;
387	         end process;
388	
389	      end generate;
390	
391	      fifoValid <= fifoValidInt and fifoInFrame;
392	
393	   end generate;
394	
395	   U_LastFifoDisGen : if VALID_THOLD_G = 1 generate
396	      fifoValidLast <= '0';
397	      fifoInFrame   <= '0';
398	      fifoReadUser  <= (others => '0');
399	      fifoValid     <= fifoValidInt;
400	   end generate;
401	
402	   sideBand(0) <= resize(fifoReadUser, 8);  -- mTLastTUser
403	
404	   -- Map output Signals
405	   fifoReadMaster <= toAxiStreamMaster (fifoDout, fifoValid, FIFO_CONFIG_C);
406	
407	   fifoRead     <= fifoReadSlave.tReady and fifoValid;
408	   fifoReadLast <= fifoReadSlave.tReady and fifoValid and fifoReadMaster.tLast;
409	
410	   -------------------------
411	   -- Master Resize
412	   -------------------------
413	   U_MasterResize : entity surf.AxiStreamGearbox
414	      generic map (
415	         TPD_G               => TPD_G,
416	         RST_POLARITY_G      => RST_POLARITY_G,
417	         RST_ASYNC_G         => RST_ASYNC_G,
418	         READY_EN_G          => true,
419	         SIDE_BAND_WIDTH_G   => 8,
420	         SLAVE_AXI_CONFIG_G  => FIFO_CONFIG_C,
421	         MASTER_AXI_CONFIG_G => MASTER_AXI_CONFIG_G)
422	      port map (
423	         axisClk     => mAxisClk,
424	         axisRst     => mAxisRst,
425	         sAxisMaster => fifoReadMaster,
426	         sSideBand   => sideBand(0),
427	         sAxisSlave  => fifoReadSlave,
428	         mAxisMaster => axisMaster,
429	         mSideBand   => sideBand(1),
430	         mAxisSlave  => axisSlave);
431	
432	   -------------------------
433	   -- Idle Generation
434	   -------------------------
435	   -- Synchronize master side tvalid back to slave side ctrl.idle
436	   -- This is a total hack
437	   Synchronizer_1 : entity surf.Synchronizer
438	      generic map (
439	         TPD_G          => TPD_G,
440	         RST_POLARITY_G => RST_POLARITY_G,
441	         RST_ASYNC_G    => RST_ASYNC_G,
442	         OUT_POLARITY_G => '0')         -- invert
443	      port map (
444	         clk     => sAxisClk,
445	         rst     => sAxisRst,
446	         dataIn  => axisMaster.tValid,
447	         dataOut => sAxisCtrl.idle);
448	
449	   -------------------------
450	   -- Pipeline Logic
451	   -------------------------
452	
453	   U_Pipe : entity surf.AxiStreamPipeline
454	      generic map (
455	         TPD_G             => TPD_G,
456	         RST_POLARITY_G    => RST_POLARITY_G,
457	         RST_ASYNC_G       => RST_ASYNC_G,
458	         SIDE_BAND_WIDTH_G => 8,
459	         PIPE_STAGES_G     => PIPE_STAGES_G)
460	      port map (
461	         -- Clock and Reset
462	         axisClk     => mAxisClk,
463	         axisRst     => mAxisRst,
464	         -- Slave Port
465	         sAxisMaster => axisMaster,
466	         sSideBand   => sideBand(1),
467	         sAxisSlave  => axisSlave,
468	         -- Master Port
469	         mAxisMaster => mAxisMaster,
470	         mSideBand   => mTLastTUser,
471	         mAxisSlave  => mAxisSlave);
472	
473	end rtl;
474

