1	-------------------------------------------------------------------------------
2	-- Company    : SLAC National Accelerator Laboratory
3	-------------------------------------------------------------------------------
4	-- Description:
5	-- Block to resize AXI Streams. Re-sizing is always little endian.
6	-- Resizer should not be used when interleaving tDests
7	-------------------------------------------------------------------------------
8	-- This file is part of 'SLAC Firmware Standard Library'.
9	-- It is subject to the license terms in the LICENSE.txt file found in the
10	-- top-level directory of this distribution and at:
11	--    https://confluence.slac.stanford.edu/display/ppareg/LICENSE.html.
12	-- No part of 'SLAC Firmware Standard Library', including this file,
13	-- may be copied, modified, propagated, or distributed except according to
14	-- the terms contained in the LICENSE.txt file.
15	-------------------------------------------------------------------------------
16	
17	library ieee;
18	use ieee.std_logic_1164.all;
19	use ieee.std_logic_unsigned.all;
20	use ieee.std_logic_arith.all;
21	
22	library surf;
23	use surf.StdRtlPkg.all;
24	use surf.AxiStreamPkg.all;
25	
26	entity AxiStreamResize is
27	   generic (
28	      -- General Configurations
29	      TPD_G             : time     := 1 ns;
30	      RST_POLARITY_G    : sl       := '1';  -- '1' for active HIGH reset, '0' for active LOW reset
31	      RST_ASYNC_G       : boolean  := false;
32	      READY_EN_G        : boolean  := true;
33	      PIPE_STAGES_G     : natural  := 0;
34	      SIDE_BAND_WIDTH_G : positive := 1;    -- General purpose sideband
35	
36	      -- AXI Stream Port Configurations
37	      SLAVE_AXI_CONFIG_G  : AxiStreamConfigType;
38	      MASTER_AXI_CONFIG_G : AxiStreamConfigType);
39	   port (
40	
41	      -- Clock and reset
42	      axisClk : in sl;
43	      axisRst : in sl;
44	
45	      -- Slave Port
46	      sAxisMaster : in  AxiStreamMasterType;
47	      sSideBand   : in  slv(SIDE_BAND_WIDTH_G-1 downto 0) := (others => '0');
48	      sAxisSlave  : out AxiStreamSlaveType;
49	
50	      -- Master Port
51	      mAxisMaster : out AxiStreamMasterType;
52	      mSideBand   : out slv(SIDE_BAND_WIDTH_G-1 downto 0);
53	      mAxisSlave  : in  AxiStreamSlaveType);
54	end AxiStreamResize;
55	
56	architecture rtl of AxiStreamResize is
57	
58	   constant SLV_BYTES_C : positive := SLAVE_AXI_CONFIG_G.TDATA_BYTES_C;
59	   constant MST_BYTES_C : positive := MASTER_AXI_CONFIG_G.TDATA_BYTES_C;
60	
61	   constant SLV_USER_C : positive := ite(SLAVE_AXI_CONFIG_G.TUSER_BITS_C /= 0, SLAVE_AXI_CONFIG_G.TUSER_BITS_C, 1);
62	   constant MST_USER_C : positive := ite(MASTER_AXI_CONFIG_G.TUSER_BITS_C /= 0, MASTER_AXI_CONFIG_G.TUSER_BITS_C, 1);
63	
64	   constant COUNT_C : positive := ite(SLV_BYTES_C > MST_BYTES_C, SLV_BYTES_C / MST_BYTES_C, MST_BYTES_C / SLV_BYTES_C);
65	
66	   type RegType is record
67	      count    : slv(bitSize(COUNT_C)-1 downto 0);
68	      obMaster : AxiStreamMasterType;
69	      sideBand : slv(SIDE_BAND_WIDTH_G-1 downto 0);
70	      ibSlave  : AxiStreamSlaveType;
71	   end record RegType;
72	
73	   constant REG_INIT_C : RegType := (
74	      count    => (others => '0'),
75	      obMaster => axiStreamMasterInit(MASTER_AXI_CONFIG_G),
76	      sideBand => (others => '0'),
77	      ibSlave  => AXI_STREAM_SLAVE_INIT_C
78	      );
79	
80	   signal r   : RegType := REG_INIT_C;
81	   signal rin : RegType;
82	
83	   signal pipeAxisMaster : AxiStreamMasterType;
84	   signal pipeSideBand   : slv(SIDE_BAND_WIDTH_G-1 downto 0);
85	   signal pipeAxisSlave  : AxiStreamSlaveType;
86	
87	begin
88	
89	   -- Make sure data widths are appropriate.
90	   assert ((SLV_BYTES_C >= MST_BYTES_C and SLV_BYTES_C mod MST_BYTES_C = 0) or
91	           (MST_BYTES_C >= SLV_BYTES_C and MST_BYTES_C mod SLV_BYTES_C = 0))
92	      report "Data widths must be even number multiples of each other" & LF &
93	      "SLV_BYTES_C= " & integer'image(SLV_BYTES_C) & LF &
94	      "MST_BYTES_C= " & integer'image(MST_BYTES_C)
95	      severity failure;
96	
97	   -- When going from a large bus to a small bus, ready is necessary
98	   assert (SLV_BYTES_C <= MST_BYTES_C or READY_EN_G = true)
99	      report "READY_EN_G must be true if slave width is great than master" severity failure;
100	
101	   -- Can't use tkeep_fixed on master side when resizing or if not on slave side
102	   assert (not (MASTER_AXI_CONFIG_G.TKEEP_MODE_C = TKEEP_FIXED_C and
103	                SLAVE_AXI_CONFIG_G.TKEEP_MODE_C /= TKEEP_FIXED_C))
104	      report "AxiStreamResize: Can't have TKEEP_MODE = TKEEP_FIXED on master side if not on slave side"
105	      severity failure;
106	
107	   comb : process (pipeAxisSlave, r, sAxisMaster, sSideBand) is
108	      variable v       : RegType;
109	      variable ibM     : AxiStreamMasterType;
110	      variable ibSide  : slv(SIDE_BAND_WIDTH_G-1 downto 0);
111	      variable idx     : integer;       -- index version of counter
112	      variable byteCnt : integer;  -- Number of valid bytes in incoming bus
113	      variable bytes   : integer;       -- byte version of counter
114	   begin
115	      v     := r;
116	      idx   := conv_integer(r.count);
117	      bytes := (idx+1) * MST_BYTES_C;
118	      if (SLAVE_AXI_CONFIG_G.TKEEP_MODE_C = TKEEP_COUNT_C) then
119	         byteCnt := conv_integer(sAxisMaster.tKeep(bitSize(SLAVE_AXI_CONFIG_G.TDATA_BYTES_C)-1 downto 0));
120	      else
121	         byteCnt := getTKeep(sAxisMaster.tKeep, SLAVE_AXI_CONFIG_G);
122	      end if;
123	
124	      -- Init ready
125	      v.ibSlave.tReady := '0';
126	
127	      -- Choose ready source and clear valid
128	      if READY_EN_G = false or pipeAxisSlave.tReady = '1' then
129	         v.obMaster.tValid := '0';
130	      end if;
131	
132	      -- Inbound data with normalized user bits (8 user bits)
133	      ibM       := sAxisMaster;
134	      ibSide    := sSideBand;
135	      ibM.tUser := (others => '0');
136	      if (SLAVE_AXI_CONFIG_G.TKEEP_MODE_C = TKEEP_COUNT_C) then
137	         ibM.tKeep := genTKeep(byteCnt);
138	      end if;
139	
140	      -- Check that both master and slave using tUser
141	      if (SLAVE_AXI_CONFIG_G.TUSER_BITS_C /= 0) and
142	         (MASTER_AXI_CONFIG_G.TUSER_BITS_C /= 0) and
143	         (SLAVE_AXI_CONFIG_G.TUSER_MODE_C /= TUSER_NONE_C) and
144	         (MASTER_AXI_CONFIG_G.TUSER_MODE_C /= TUSER_NONE_C) then
145	         -- Loop through the tUser bit field
146	         for i in 0 to AXI_STREAM_MAX_TKEEP_WIDTH_C-1 loop
147	            ibM.tUser((i*8)+(SLV_USER_C-1) downto (i*8)) := sAxisMaster.tUser((i*SLV_USER_C)+(SLV_USER_C-1) downto (i*SLV_USER_C));
148	         end loop;
149	      end if;
150	
151	      -- Pipeline advance
152	      if v.obMaster.tValid = '0' then
153	
154	         -- Increasing size
155	         if MST_BYTES_C > SLV_BYTES_C then
156	            v.ibSlave.tReady := '1';
157	
158	            -- init when count = 0
159	            if (r.count = 0) then
160	               v.obMaster       := axiStreamMasterInit(MASTER_AXI_CONFIG_G);
161	               v.obMaster.tKeep := (others => '0');
162	               v.obMaster.tStrb := (others => '0');
163	            end if;
164	
165	            v.obMaster.tData((SLV_BYTES_C*8*idx)+((SLV_BYTES_C*8)-1) downto (SLV_BYTES_C*8*idx)) := ibM.tData((SLV_BYTES_C*8)-1 downto 0);
166	            v.obMaster.tUser((SLV_BYTES_C*8*idx)+((SLV_BYTES_C*8)-1) downto (SLV_BYTES_C*8*idx)) := ibM.tUser((SLV_BYTES_C*8)-1 downto 0);
167	            v.obMaster.tStrb((SLV_BYTES_C*idx)+(SLV_BYTES_C-1) downto (SLV_BYTES_C*idx))         := ibM.tStrb(SLV_BYTES_C-1 downto 0);
168	            v.obMaster.tKeep((SLV_BYTES_C*idx)+(SLV_BYTES_C-1) downto (SLV_BYTES_C*idx))         := ibM.tKeep(SLV_BYTES_C-1 downto 0);
169	
170	            v.obMaster.tId   := ibM.tId;
171	            v.obMaster.tDest := ibM.tDest;
172	            v.obMaster.tLast := ibM.tLast;
173	            v.sideBand       := ibSide;
174	
175	            -- Determine if we move data
176	            if ibM.tValid = '1' then
177	               if r.count = (COUNT_C-1) or ibM.tLast = '1' then
178	                  v.obMaster.tValid := '1';
179	                  v.count           := (others => '0');
180	               else
181	                  v.count := r.count + 1;
182	               end if;
183	            end if;
184	
185	         -- Decreasing size
186	         else
187	
188	            v.obMaster := axiStreamMasterInit(MASTER_AXI_CONFIG_G);
189	
190	            v.obMaster.tData((MST_BYTES_C*8)-1 downto 0) := ibM.tData((MST_BYTES_C*8*idx)+((MST_BYTES_C*8)-1) downto (MST_BYTES_C*8*idx));
191	            v.obMaster.tUser((MST_BYTES_C*8)-1 downto 0) := ibM.tUser((MST_BYTES_C*8*idx)+((MST_BYTES_C*8)-1) downto (MST_BYTES_C*8*idx));
192	            v.obMaster.tStrb(MST_BYTES_C-1 downto 0)     := ibM.tStrb((MST_BYTES_C*idx)+(MST_BYTES_C-1) downto (MST_BYTES_C*idx));
193	            v.obMaster.tKeep(MST_BYTES_C-1 downto 0)     := ibM.tKeep((MST_BYTES_C*idx)+(MST_BYTES_C-1) downto (MST_BYTES_C*idx));
194	
195	            v.obMaster.tId   := ibM.tId;
196	            v.obMaster.tDest := ibM.tDest;
197	            v.sideBand       := ibSide;
198	
199	            -- Determine if we move data
200	            if ibM.tValid = '1' then
201	               if (r.count = (COUNT_C-1)) or ((bytes >= byteCnt) and (ibM.tLast = '1')) then
202	                  v.count          := (others => '0');
203	                  v.ibSlave.tReady := '1';
204	                  v.obMaster.tLast := ibM.tLast;
205	               else
206	                  v.count          := r.count + 1;
207	                  v.ibSlave.tReady := '0';
208	                  v.obMaster.tLast := '0';
209	               end if;
210	            end if;
211	
212	            -- Drop transfers with no tKeep bits set, except on tLast
213	            v.obMaster.tValid := ibM.tValid and (uOr(v.obMaster.tKeep(COUNT_C-1 downto 0)) or v.obMaster.tLast);
214	
215	         end if;
216	      end if;
217	
218	      -- Resize disabled
219	      if SLV_BYTES_C = MST_BYTES_C then
220	         sAxisSlave     <= pipeAxisSlave;
221	         pipeAxisMaster <= sAxisMaster;
222	         pipeSideBand   <= sSideBand;
223	
224	         -- Check for TKEEP_COUNT_C mode on either side
225	         if (SLAVE_AXI_CONFIG_G.TKEEP_MODE_C = TKEEP_COUNT_C) or (MASTER_AXI_CONFIG_G.TKEEP_MODE_C = TKEEP_COUNT_C) then
226	
227	            -- Check for TKEEP_COUNT_C mode on slave side only
228	            if (SLAVE_AXI_CONFIG_G.TKEEP_MODE_C = TKEEP_COUNT_C) and (MASTER_AXI_CONFIG_G.TKEEP_MODE_C /= TKEEP_COUNT_C) then
229	               pipeAxisMaster.tkeep <= genTKeep(conv_integer(sAxisMaster.tkeep(bitSize(SLAVE_AXI_CONFIG_G.TDATA_BYTES_C)-1 downto 0)));
230	
231	            -- Check for TKEEP_COUNT_C mode on master side only
232	            elsif (SLAVE_AXI_CONFIG_G.TKEEP_MODE_C /= TKEEP_COUNT_C) and (MASTER_AXI_CONFIG_G.TKEEP_MODE_C = TKEEP_COUNT_C) then
233	               pipeAxisMaster.tkeep <= toSlv(getTKeep(sAxisMaster.tKeep, SLAVE_AXI_CONFIG_G), AXI_STREAM_MAX_TKEEP_WIDTH_C);
234	
235	            -- Else both sides are TKEEP_COUNT_C mode
236	            else
237	               null;
238	            end if;
239	         end if;
240	
241	         -- Outbound data with proper user bits
242	         pipeAxisMaster.tUser <= (others => '0');
243	         for i in 0 to AXI_STREAM_MAX_TKEEP_WIDTH_C-1 loop
244	            if (SLV_USER_C > MST_USER_C) then
245	               pipeAxisMaster.tUser((i*MST_USER_C)+(MST_USER_C-1) downto (i*MST_USER_C)) <= ibM.tUser((i*8)+(MST_USER_C-1) downto (i*8));
246	            else
247	               pipeAxisMaster.tUser((i*MST_USER_C)+(SLV_USER_C-1) downto (i*MST_USER_C)) <= ibM.tUser((i*8)+(SLV_USER_C-1) downto (i*8));
248	            end if;
249	         end loop;
250	
251	      else
252	         sAxisSlave <= v.ibSlave;
253	
254	         -- Outbound data with proper user bits
255	         pipeAxisMaster       <= r.obMaster;
256	         pipeSideBand         <= r.sideBand;
257	         pipeAxisMaster.tUser <= (others => '0');
258	         if (MASTER_AXI_CONFIG_G.TKEEP_MODE_C = TKEEP_COUNT_C) then
259	            pipeAxisMaster.tKeep <= toSlv(getTKeep(r.obMaster.tKeep, MASTER_AXI_CONFIG_G), AXI_STREAM_MAX_TKEEP_WIDTH_C);
260	         end if;
261	
262	         for i in 0 to AXI_STREAM_MAX_TKEEP_WIDTH_C-1 loop
263	            pipeAxisMaster.tUser((i*MST_USER_C)+(MST_USER_C-1) downto (i*MST_USER_C)) <= r.obMaster.tUser((i*8)+(MST_USER_C-1) downto (i*8));
264	         end loop;
265	      end if;
266	
267	      rin <= v;
268	
269	   end process comb;
270	
271	   seq : process (axisClk, axisRst) is
272	   begin
273	      if (RST_ASYNC_G) and (axisRst = RST_POLARITY_G or (SLV_BYTES_C = MST_BYTES_C)) then
274	         r <= REG_INIT_C after TPD_G;
275	      elsif (rising_edge(axisClk)) then
276	         if (RST_ASYNC_G = false) and (axisRst = RST_POLARITY_G or (SLV_BYTES_C = MST_BYTES_C)) then
277	            r <= REG_INIT_C after TPD_G;
278	         else
279	            r <= rin after TPD_G;
280	         end if;
281	      end if;
282	   end process seq;
283	
284	   -- Optional output pipeline registers to ease timing
285	   AxiStreamPipeline_1 : entity surf.AxiStreamPipeline
286	      generic map (
287	         TPD_G             => TPD_G,
288	         RST_POLARITY_G    => RST_POLARITY_G,
289	         RST_ASYNC_G       => RST_ASYNC_G,
290	         SIDE_BAND_WIDTH_G => SIDE_BAND_WIDTH_G,
291	         PIPE_STAGES_G     => PIPE_STAGES_G)
292	      port map (
293	         axisClk     => axisClk,
294	         axisRst     => axisRst,
295	         sAxisMaster => pipeAxisMaster,
296	         sSideBand   => pipeSideBand,
297	         sAxisSlave  => pipeAxisSlave,
298	         mAxisMaster => mAxisMaster,
299	         mSideBand   => mSideBand,
300	         mAxisSlave  => mAxisSlave);
301	
302	end rtl;
